// ============================================
// NODE: Load All Resume Data
// Contains JD + All Candidate Resumes
// ============================================

const jd = `
Role: Data Analyst
Required Skills: SQL, Python, Excel, Data Analytics, Reporting
Nice to Have: Tableau, Power BI, Machine Learning, Google Analytics, R
Experience: 2+ years in data analysis
Education: Bachelor's in CS, Statistics, or related field
`;

const resumes = [
  {
    name: "Priya Sharma",
    email: "iamhimanshuhb+priya@gmail.com",
    phone: "9876543210",
    position: "Data Analyst",
    resume_text: "Data Analyst at Analytics Co for 3 years. Built SQL queries for daily reporting with 500K rows. Created Power BI dashboards for sales team. Used Python pandas for data cleaning pipelines. Reduced report generation time by 40%. Junior Analyst at StartupXYZ for 1 year doing Excel financial modeling and AB test analysis. B.Tech Computer Science Delhi University 2019. Skills: SQL, Python, pandas, numpy, Power BI, Excel, Tableau, Git, analytics, data"
  },
  {
    name: "Rahul Verma",
    email: "iamhimanshuhb+rahul@gmail.com",
    phone: "9876543211",
    position: "Data Analyst",
    resume_text: "Marketing Executive at BrandCo for 2 years. Managed social media campaigns. Created monthly performance reports in basic Excel. Coordinated with design team. Intern at AdAgency for 6 months doing campaign planning and basic data entry. BBA Marketing Mumbai University 2021. Skills: MS Office, Canva, Google Ads, Instagram Ads, Basic Excel"
  },
  {
    name: "Ananya Patel",
    email: "iamhimanshuhb+ananya@gmail.com",
    phone: "9876543212",
    position: "Data Analyst",
    resume_text: "Business Intelligence Analyst at FinServ Ltd for 2.5 years. Developed complex SQL queries and stored procedures. Built Tableau dashboards for C-suite reporting. Moderate Python experience in scripting and automation. Worked with Google Analytics for web data analysis. B.Sc Statistics Pune University 2020. Skills: SQL, Tableau, Python, Excel, Google Analytics, analytics, data, reporting"
  },
  {
    name: "Kiran Mehta",
    email: "iamhimanshuhb+kiran@gmail.com",
    phone: "9876543213",
    position: "Data Analyst",
    resume_text: "Software Developer at TechStart for 3 years. Backend development in Java and Python. Database management with PostgreSQL and MySQL. Some data pipeline work. No dedicated analytics or BI experience. B.E. Computer Engineering 2020. Skills: Java, Python, SQL, PostgreSQL, REST APIs, Git"
  },
  {
    name: "Sneha Rao",
    email: "iamhimanshuhb+sneha@gmail.com",
    phone: "9876543214",
    position: "Data Analyst",
    resume_text: "Senior Data Analyst at E-commerce Giant for 4 years. Advanced SQL with window functions CTEs and optimization. Python for ML pipelines using scikit-learn and pandas. Power BI and Tableau certified. Led dashboard migration project saving 20 hours per week. Mentored 2 junior analysts. M.Sc Data Science IIT Bombay 2019. Skills: SQL, Python, R, Power BI, Tableau, machine learning, Excel, Google Analytics, analytics, data, senior, lead"
  },
  {
    name: "Arjun Nair",
    email: "iamhimanshuhb+arjun@gmail.com",
    phone: "9876543215",
    position: "Data Analyst",
    resume_text: "Data Analyst at HealthTech for 2 years. SQL reporting and dashboard creation. Basic Python for automation. Excel pivot tables and charts. Some exposure to Tableau. B.Sc Mathematics 2021. Skills: SQL, Excel, Python, Tableau, data, analytics"
  },
  {
    name: "Meera Iyer",
    email: "iamhimanshuhb+meera@gmail.com",
    phone: "9876543216",
    position: "Data Analyst",
    resume_text: "Content Writer at MediaCo for 3 years. Blog writing and SEO content. Social media management. Basic Google Analytics for traffic reporting. No SQL no Python no data analysis experience. B.A. English Literature 2020. Skills: Writing, SEO, WordPress, Google Analytics, Social Media"
  }
];

// Return each resume as a separate item with JD attached
return resumes.map(r => ({
  json: {
    ...r,
    jd: jd,
    processed_at: new Date().toISOString()
  }
}));

const resume = ($json.resume_text || '').toLowerCase();
const name = $json.name || 'Unknown';
const email = $json.email || '';
const phone = $json.phone || '';
const position = $json.position || '';

const mustHaveSkills = [
  { keyword: 'sql', label: 'SQL' },
  { keyword: 'python', label: 'Python' },
  { keyword: 'excel', label: 'Excel' },
  { keyword: 'analytics', label: 'Analytics' },
  { keyword: 'data', label: 'Data' }
];

const niceToHaveSkills = [
  { keyword: 'tableau', label: 'Tableau' },
  { keyword: 'power bi', label: 'Power BI' },
  { keyword: 'machine learning', label: 'Machine Learning' },
  { keyword: 'google analytics', label: 'Google Analytics' },
  { keyword: 'r ', label: 'R Language' }
];

const experienceKeywords = ['2 years', '3 years', '4 years', '5 years', '2.5 years', 'senior', 'lead'];
const educationKeywords = ['b.tech', 'b.sc', 'm.sc', 'bachelor', 'master', 'computer science', 'statistics', 'iit'];
const leadershipKeywords = ['led', 'managed', 'mentored', 'supervised'];

let mustHaveScore = 0;
let niceToHaveScore = 0;
let experienceScore = 0;
let educationScore = 0;
let leadershipScore = 0;
let strengths = [];
let gaps = [];
let matchedSkills = [];
let missingSkills = [];

mustHaveSkills.forEach(skill => {
  if (resume.includes(skill.keyword)) {
    mustHaveScore += 15;
    strengths.push('Strong ' + skill.label + ' skills');
    matchedSkills.push(skill.label);
  } else {
    gaps.push('Missing ' + skill.label);
    missingSkills.push(skill.label);
  }
});

niceToHaveSkills.forEach(skill => {
  if (resume.includes(skill.keyword)) {
    niceToHaveScore += 8;
    matchedSkills.push(skill.label + ' (bonus)');
  }
});

experienceKeywords.forEach(exp => {
  if (resume.includes(exp)) experienceScore = 10;
});

educationKeywords.forEach(edu => {
  if (resume.includes(edu)) educationScore = 5;
});

leadershipKeywords.forEach(lead => {
  if (resume.includes(lead)) {
    leadershipScore = 5;
    strengths.push('Demonstrates leadership');
  }
});

let totalScore = mustHaveScore + niceToHaveScore + experienceScore + educationScore + leadershipScore;
totalScore = Math.round((totalScore / 135) * 100);
totalScore = Math.min(totalScore, 100);

if (experienceScore > 0) strengths.push('Has relevant work experience');
if (educationScore > 0) strengths.push('Relevant educational background');

strengths = strengths.slice(0, 3);
gaps = gaps.slice(0, 3);

const recommendation = totalScore >= 75 ? 'Strong Fit' : totalScore >= 50 ? 'Moderate Fit' : 'Not Fit';
const status = totalScore >= 75 ? 'Selected' : 'Rejected';
const priority = totalScore >= 90 ? 'High Priority' : totalScore >= 75 ? 'Medium Priority' : totalScore >= 50 ? 'Review' : 'Rejected';

return {
  candidate_name: name,
  candidate_email: email,
  candidate_phone: phone,
  applied_position: position,
  total_score: totalScore,
  must_have_score: mustHaveScore,
  nice_to_have_score: niceToHaveScore,
  experience_score: experienceScore,
  education_score: educationScore,
  leadership_score: leadershipScore,
  must_have_coverage: Math.round((matchedSkills.filter(s => !s.includes('bonus')).length / mustHaveSkills.length) * 100) + '%',
  matched_skills: matchedSkills.join(', '),
  missing_skills: missingSkills.join(', '),
  strengths: strengths,
  gaps: gaps,
  recommendation: recommendation,
  recommendation_reason: totalScore >= 75 ? 'Meets required skills' : 'Does not meet minimum requirements',
  status: status,
  priority: priority,
  screened_at: new Date().toISOString(),
  screened_date: new Date().toLocaleDateString('en-IN')
};

const all = $input.all();

return all.map((item) => {
  return {
    json: {
      candidate_name: item.json.candidate_name,
      candidate_email: item.json.candidate_email,
      candidate_phone: item.json.candidate_phone,
      applied_position: item.json.applied_position,
      total_score: item.json.total_score,
      must_have_score: item.json.must_have_score,
      nice_to_have_score: item.json.nice_to_have_score,
      experience_score: item.json.experience_score,
      education_score: item.json.education_score,
      leadership_score: item.json.leadership_score,
      must_have_coverage: item.json.must_have_coverage,
      matched_skills: item.json.matched_skills,
      missing_skills: item.json.missing_skills,
      strengths: item.json.strengths,
      gaps: item.json.gaps,
      recommendation: item.json.recommendation,
      recommendation_reason: item.json.recommendation_reason,
      status: item.json.status,
      priority: item.json.priority,
      screened_at: item.json.screened_at,
      screened_date: item.json.screened_date
    }
  };
});
